local StructLotteryLogData = LxClass("StructLotteryLogData", nil)
function StructLotteryLogData:StructLotteryLogData()
    ---@type number 召唤次数
    self.num = 0
    ---@type StructRewardItem[] 奖励
    self.itemList = {}
    ---@type number 生成时间
    self.createTime = 0
    ---@type StructRewardItem[] 消耗物品
    self.consume = {}
