function StructLotteryLogData:CreateByPb(pb)
    self.num = pb.num

    local itemList = {}
    for i, v in ipairs(pb.itemList) do
        local item = StructRewardItem:New()
        item:CreateByPb(v)
        table.insert(itemList, item)
    end
    self.itemList = itemList

    ---@type number 生成时间
    self.createTime = checknumber(pb.createTime)

    local consume = {}
    for i,v in ipairs(pb.consume) do
        local item = StructRewardItem:New()
        item:CreateByPb(v)
        table.insert(consume, item)
    end
    self.consume = consume

    self.lotteryType = pb.lotteryType
end

return StructLotteryLogData